use actix_web::{get, web, HttpResponse, Responder};
use crate::db::models::Invoice;
use crate::db::repositories::InvoiceRepository;
use crate::security::User;

#[get("/invoices/{id}")]
async fn get_invoice(
    invoice_repo: web::Data<InvoiceRepository>,
    user: User,
    path: web::Path<String>,
) -> impl Responder {
    let invoice_id = path.into_inner();

    // Validate user permissions to access invoice
    if !user.has_permission(invoice_id) {
        return HttpResponse::Forbidden().finish();
    }

    let invoice = invoice_repo.get_by_id(invoice_id).await.unwrap_or_else(|_| {
        HttpResponse::NotFound().finish()
    });

    HttpResponse::Ok().json(invoice)
}